  function periodSet(p){var st=state(), def=latestDefaults(); st.period=p; st.page=1; if(p==='day'){st.day=st.day||def.day; st.month=monthKey(new Date(st.day)); st.year=String(new Date(st.day).getFullYear());} else if(p==='month'){st.month=st.month||def.month; st.year=String((st.month||def.month).split('-')[0]); st.day='';} else if(p==='year'){st.year=(st.year&&st.year!=='all')?st.year:def.year; st.month=''; st.day='';} else if(p==='all'){st.year='all'; st.month=''; st.day='';} st.selected=''; st.previewOpen=false; renderSalesInvoiceReport();}
